        padding-bottom: 10px;
    }
    h2 {
        color: #e67e22;
        border-left: 5px solid #e67e22;
        padding-left: 10px;
        margin-top: 30px;
    }
    .category-box {
        background: #fff;
        padding: 15px;
        border-radius: 8px;
        box-shadow: 0 2px 5px rgba(0,0,0,0.1);
        margin-bottom: 20px;
    }
    ul {
        list-style-type: none;
        padding: 0;
    }
    li {
        margin-bottom: 12px;
        padding-left: 5px;
    }
    .grammar-point {
        font-weight: bold;
        color: #c0392b;
        font-size: 1.1em;
    }
    .level-badge {
        display: inline-block;
        background: #34495e;
